script.text:
      /* <flatten type="Javascript"> */
function load$InvoiceVerification$(g) {
  g.add_commandEvent(on$InvoiceVerification$ExecuteCommand);
  g._$k = g._getColumnOrder('stt_rec');
  g._$u = g._getColumnOrder('ma_dvcs');
  g._$d = g._getColumnOrder('ngay_ct');
  g._$n = g._getColumnOrder('so_ct_hddt');
  g._$l = g._getColumnOrder('so_seri_hddt');
  g._$m = g._getColumnOrder('tinh_trang');
  g._$p = g._getColumnOrder('tinh_trang_hddt');
  g._$t = g._getColumnOrder('kieu_ph');
  g._$h = g._getColumnOrder('thanh_toan');
  g._$q = g._getColumnOrder('trang_thai_tt');
  g._$s = g._getColumnOrder('dich_vu_hddt');
}
function dispose$InvoiceVerification$(g) {try {g.remove_commandEvent(on$InvoiceVerification$ExecuteCommand);} catch (ex) {}}
function on$InvoiceVerification$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, id = g.get_id();
  switch (action) {
    case 'Verify':
      if (g._activeRow == -1) break;
      var c = g._getItemValue(g._activeRow, g._$p), t = g._getItemValue(g._activeRow, g._$q);
      if ((c == '2') || (c == '3')) {
        if (t != 1) break;
      }
      else {
        if ((c != '1') && (c != '8')) break;
      }
      var msg = ((g._language == 'v') ? 'Hệ thống sẽ <span class="Highlight">kiểm tra và cập nhật lại thông tin hóa đơn đang được chọn</span>, bạn có chắc chắn thực hiện không?' : 'Are you sure you want to <span class="Highlight">verify the selected invoice</span>?');
      $message.show(msg, 0, String.format('request$InvoiceVerification($find(\'{0}\'));', id), String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    default:
      break;
  }
}
function request$InvoiceVerification(g, force) {
  var id = g._id;
  if (!force) {
     $func.showWait(id);
     window.setTimeout(function() {request$InvoiceVerification(g, true);}, 2);
     return;
  }
  var query = Sys.Serialization.JavaScriptSerializer.serialize({
    'unit': g._getItemValue(g._activeRow, g._$u),
    'voucherCode': g._$voucherCode,
    'idNumber': g._getItemValue(g._activeRow, g._$k),
    'listDays': '',
  });

  Sys.Net.WebServiceProxy.invoke($func.resolveClientUrl(g._url$EInvoice, g._baseUrl), g._service$Method, false, {
      method: '370',
      action: null,
      query: query
  }, onRequest$InvoiceVerification$Completed, onRequest$InvoiceVerification$Failed, g._id);
}
function onRequest$InvoiceVerification$Completed(r, id) {
  var g = $find(id), v = g._language == 'v', d = r.Data;
  if (r.Success == '1') set$InvoiceVerificationValue(g, d[0], d[2], d[3], d[4], v, id);
  else {
    $func.hideWait(id);
    g._busy(false);
    $message.show((v ? 'Phát sinh lỗi trong quá trình thực hiện.' : 'The process was failed.'), String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
  }
}
function set$InvoiceVerificationValue(g, n, l, p, t, v, id) {
  var s = ['0', '1', '2', '3', '9', '8', '4'], payment = g._getItemValue(g._activeRow, g._$s);
  if (n != '' || g._getItemValue(g._activeRow, g._$t) != 1) {
    g._setItemValue(g._activeRow, g._$n, n);
    g._setItemValue(g._activeRow, g._$l, l);
    g._setItemValue(g._activeRow, g._$p, p);
    g._setItemValue(g._activeRow, g._$m, g._$a[s.indexOf(p)]);
    g._setItemValue(g._activeRow, g._$q, (t == 1 ? 2 : 0));
    if (payment == 1 || payment == 8) g._setItemValue(g._activeRow, g._$h, (t == 1 ? g._$b[2] : g._$b[0]));
  }
  $func.hideWait(id);
  g._busy(false);
  $message.show(v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.', String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
}
function onRequest$InvoiceVerification$Failed(e, id) {
  var g = $find(id);
  $func.hideWait(id);
  g._busy(false);
  $message.showError(e);
}
/* </flatten> */
      &JavascriptReportInit;
